#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int flag = 0;
        for (int i = 0; i < N - 1; i++) {
            if (abs(arr[i] - arr[i + 1]) > 1) {
                flag = 1;
                break;
            }
        }
        if (flag) {
            printf("NO\n");
        } else {
            printf("YES\n");
        }
        free(arr);
    }
    return 0;
}

